// UTILS
const uid=()=>Date.now().toString(36)+Math.random().toString(36).slice(2,7);
const hashPw=(pw)=>btoa("rg_salt_"+pw+"_rg");
const fmtDate=(d)=>{if(!d)return"";return new Date(d).toLocaleDateString("es-ES",{day:"2-digit",month:"2-digit",year:"numeric"});};
const fmtDateTime=(d)=>{if(!d)return"";const dt=new Date(d);return dt.toLocaleDateString("es-ES",{day:"2-digit",month:"2-digit",year:"numeric"})+" "+dt.toLocaleTimeString("es-ES",{hour:"2-digit",minute:"2-digit",second:"2-digit"});};
const fmtTime=(d)=>new Date(d).toLocaleTimeString("es-ES",{hour:"2-digit",minute:"2-digit",second:"2-digit"});
const toISO=(d)=>{const dt=new Date(d);return `${dt.getFullYear()}-${String(dt.getMonth()+1).padStart(2,"0")}-${String(dt.getDate()).padStart(2,"0")}`;};
const todayStr=()=>toISO(new Date());
function calcBizDays(from,to){if(!from||!to)return 0;let c=0;const d=new Date(from);const e=new Date(to);while(d<=e){if(d.getDay()!==0&&d.getDay()!==6)c++;d.setDate(d.getDate()+1);}return c;}
function detectPlatform(){const u=navigator.userAgent;if(/Android/i.test(u))return"Android";if(/iPhone|iPad/i.test(u))return"iOS";if(/Windows/i.test(u))return"Windows";if(/Mac/i.test(u))return"macOS";if(/Linux/i.test(u))return"Linux";return"Otro";}
const getScreenRes=()=>`${window.screen.width}x${window.screen.height}`;
const MONTHS_ES=["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];
const MONTHS_SHORT=["Ene","Feb","Mar","Abr","May","Jun","Jul","Ago","Sep","Oct","Nov","Dic"];
const DAYS_ES=["Domingo","Lunes","Martes","Miércoles","Jueves","Viernes","Sábado"];
const fullDateStr=(d)=>`${DAYS_ES[d.getDay()]}, ${d.getDate()} de ${MONTHS_ES[d.getMonth()]} de ${d.getFullYear()}`;
function genCSV(h,rows){return"\uFEFF"+h.join(";")+"\n"+rows.map(r=>r.map(c=>`"${String(c??"").replace(/"/g,'""')}"`).join(";")).join("\n");}
function downloadFile(c,fn,m="text/csv;charset=utf-8"){const b=new Blob([c],{type:m});const u=URL.createObjectURL(b);const a=document.createElement("a");a.href=u;a.download=fn;a.click();URL.revokeObjectURL(u);}

