// DEMO DATA - 30+ users
function createDemoData(){
  const NAMES=["Carlos López","Ana Martínez","Pedro Ruiz","Laura Fernández","Miguel Ángel Díaz","Carmen Moreno","Andrés Navarro","Paula Domínguez","Francisco Gil","Isabel Vázquez","Daniel Muñoz","Marta Álvarez","Alberto Castro","Raquel Ortega","Sergio Marín","Natalia Iglesias","Alejandro Rubio","Cristina Molina","Iván Serrano","Sandra Blanco","Óscar Suárez","Patricia Medina","Hugo Herrero","Silvia Peña","Adrián Crespo","Beatriz Ramos"];
  const RESP=[{id:"r1",name:"María García"},{id:"r2",name:"Javier Sánchez"},{id:"r3",name:"Elena Torres"},{id:"r4",name:"Roberto Jiménez"}];
  const mkEmail=(n)=>n.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/ /g,".")+"@registro.es";
  const users=[{id:"u1",name:"Administrador",email:"admin@registro.es",password:hashPw("admin123"),role:"admin",active:true,createdAt:"2024-01-01T09:00:00",responsableId:null}];
  RESP.forEach(r=>{users.push({id:r.id,name:r.name,email:mkEmail(r.name),password:hashPw("resp123"),role:"responsable",active:true,createdAt:"2024-01-10T09:00:00",responsableId:"u1"});});
  NAMES.forEach((n,i)=>{users.push({id:`e${i+1}`,name:n,email:mkEmail(n),password:hashPw("user123"),role:"usuario",active:i<24,createdAt:`2024-${String(Math.floor(i/5)+1).padStart(2,"0")}-${String((i%28)+1).padStart(2,"0")}T09:00:00`,responsableId:RESP[i%4].id});});

  const vacPools={};
  users.filter(u=>u.role!=="admin").forEach(u=>{vacPools[u.id]={[CURRENT_YEAR]:{total:22,active:true},[CURRENT_YEAR-1]:{total:22,active:Math.random()>0.3}};});

  const y=CURRENT_YEAR;const nonAdmin=users.filter(u=>u.role!=="admin");
  const solicitudes=[];const fichajes=[];const horasExtra=[];const compensaciones=[];

  nonAdmin.forEach((u,i)=>{
    const s1=1+(i%20),e1=Math.min(s1+5+(i%8),31);
    solicitudes.push({id:`sv${i}`,userId:u.id,type:"vacaciones",vacYear:y,dateFrom:`${y}-07-${String(s1).padStart(2,"0")}`,dateTo:`${y}-07-${String(e1).padStart(2,"0")}`,description:"Vacaciones verano",status:"aprobada",createdAt:`${y}-05-${String((i%28)+1).padStart(2,"0")}T10:00:00`,reviewedBy:u.responsableId,reviewedAt:`${y}-05-${String(Math.min((i%28)+2,28)).padStart(2,"0")}T09:00:00`});
    if(i%3===0){const s2=1+(i%15);solicitudes.push({id:`sa${i}`,userId:u.id,type:"vacaciones",vacYear:y,dateFrom:`${y}-08-${String(s2).padStart(2,"0")}`,dateTo:`${y}-08-${String(Math.min(s2+5,28)).padStart(2,"0")}`,description:"Agosto",status:i%6===0?"pendiente":"aprobada",createdAt:`${y}-06-${String((i%28)+1).padStart(2,"0")}T10:00:00`,reviewedBy:i%6===0?null:u.responsableId,reviewedAt:i%6===0?null:`${y}-06-15T09:00:00`});}
    if(i%4===0)solicitudes.push({id:`si${i}`,userId:u.id,type:"consulta_medica",vacYear:null,dateFrom:`${y}-03-${String((i%28)+1).padStart(2,"0")}`,dateTo:`${y}-03-${String((i%28)+1).padStart(2,"0")}`,description:"Revisión",status:"aprobada",createdAt:`${y}-03-01T08:00:00`,reviewedBy:u.responsableId,reviewedAt:`${y}-03-02T09:00:00`});
    if(i%7===0)solicitudes.push({id:`sm${i}`,userId:u.id,type:"asuntos_propios",vacYear:null,dateFrom:`${y}-04-${String((i%20)+5).padStart(2,"0")}`,dateTo:`${y}-04-${String((i%20)+5).padStart(2,"0")}`,description:"Asunto personal",status:"pendiente",createdAt:`${y}-04-01T10:00:00`,reviewedBy:null,reviewedAt:null});

    const td=new Date();
    for(let d=1;d<=15;d++){const day=new Date(td);day.setDate(day.getDate()-d);if(day.getDay()===0||day.getDay()===6)continue;const ds=toISO(day);const eH=7+(i%3),eM=Math.floor(Math.random()*30),sH=eH+8+Math.floor(Math.random()*2),sM=Math.floor(Math.random()*59);
      const et=new Date(day);et.setHours(eH,eM,0);const st=new Date(day);st.setHours(sH,sM,0);
      fichajes.push({id:uid(),userId:u.id,date:ds,type:"entrada",userTime:et.toISOString(),serverTime:et.toISOString(),timeDiff:Math.floor(Math.random()*500)});
      if(d%3===0){const p1=new Date(day);p1.setHours(13,Math.floor(Math.random()*30),0);const p2=new Date(day);p2.setHours(14,Math.floor(Math.random()*15),0);fichajes.push({id:uid(),userId:u.id,date:ds,type:"pausa_comida",userTime:p1.toISOString(),serverTime:p1.toISOString(),timeDiff:0});fichajes.push({id:uid(),userId:u.id,date:ds,type:"fin_pausa",userTime:p2.toISOString(),serverTime:p2.toISOString(),timeDiff:0});}
      fichajes.push({id:uid(),userId:u.id,date:ds,type:"salida",userTime:st.toISOString(),serverTime:st.toISOString(),timeDiff:Math.floor(Math.random()*800)});
    }
    if(i%3===0)horasExtra.push({id:`he${i}`,userId:u.id,fecha:`${y}-04-${String((i%28)+1).padStart(2,"0")}`,horas:2+(i%6),motivo:["Cierre trimestral","Proyecto especial","Inventario","Guardia","Formación","Auditoría"][i%6],registradoPor:u.responsableId,createdAt:`${y}-04-15T09:00:00`});
    if(i%5===0)compensaciones.push({id:`co${i}`,userId:u.id,dias:1,origen:"Compensación horas extra",fecha:`${y}-05-15`,registradoPor:u.responsableId,createdAt:`${y}-05-15T09:00:00`});
  });

  const festivos=[`${y}-01-01`,`${y}-01-06`,`${y}-05-01`,`${y}-08-15`,`${y}-10-12`,`${y}-11-01`,`${y}-12-06`,`${y}-12-08`,`${y}-12-25`];
  const mensajes=[{id:"m1",authorId:"u1",title:"Bienvenida al sistema",body:"Se ha puesto en marcha el nuevo sistema de control horario. Es obligatorio fichar diariamente.",targetUsers:nonAdmin.map(u=>u.id),readBy:nonAdmin.slice(0,25).map(u=>u.id),active:true,createdAt:`${y}-01-15T09:00:00`},{id:"m2",authorId:"u1",title:"Política de vacaciones",body:"Las vacaciones deben solicitarse con 15 días de antelación mínima.",targetUsers:nonAdmin.map(u=>u.id),readBy:nonAdmin.slice(0,20).map(u=>u.id),active:true,createdAt:`${y}-03-01T09:00:00`}];

  return{config:{incidencias:{...DEFAULT_INCIDENCIAS},horasExtraPorDia:8},users,userConfig:{},vacPools,fichajes,solicitudes,documentos:[],mensajes,horasExtra,compensaciones,accessLogs:[],festivos};
}

// UI COMPONENTS
const bc={aprobada:{bg:C.greenLight,c:"#065F46"},pendiente:{bg:C.amberLight,c:"#92400E"},rechazada:{bg:C.redLight,c:"#991B1B"},admin:{bg:C.redLight,c:C.red},responsable:{bg:C.blueLight,c:"#1E40AF"},usuario:{bg:C.grayLight,c:C.gray},activo:{bg:C.greenLight,c:"#065F46"},inactivo:{bg:C.grayLight,c:C.gray},ok:{bg:C.greenLight,c:"#065F46"},fallo:{bg:C.redLight,c:"#991B1B"},info:{bg:C.blueLight,c:"#1E40AF"},purple:{bg:C.purpleLight,c:"#5B21B6"}};
function Badge({text,type="info",style:es={}}){const b=bc[type]||bc.info;return<span style={{display:"inline-block",padding:"2px 10px",borderRadius:999,fontSize:12,fontWeight:600,background:b.bg,color:b.c,whiteSpace:"nowrap",...es}}>{text}</span>;}
function Modal({title,onClose,children,width=540}){return<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.4)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,padding:16}} onClick={onClose}><div style={{background:C.white,borderRadius:16,width:"100%",maxWidth:width,maxHeight:"90vh",overflow:"auto",boxShadow:"0 25px 50px rgba(0,0,0,0.15)"}} onClick={e=>e.stopPropagation()}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"20px 24px",borderBottom:`1px solid ${C.border}`}}><h3 style={{margin:0,fontSize:18,fontWeight:700,color:C.text}}>{title}</h3><button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",padding:4}}><Icon name="x" size={20} color={C.textLight}/></button></div><div style={{padding:24}}>{children}</div></div></div>;}
function Card({children,style={},onClick}){return<div onClick={onClick} style={{background:C.white,border:`1px solid ${C.border}`,borderRadius:12,padding:20,boxShadow:"0 1px 3px rgba(0,0,0,0.04)",cursor:onClick?"pointer":"default",...style}}>{children}</div>;}
function Btn({children,onClick,color=C.red,textColor="#fff",disabled,full,size="md",style:extra={},icon}){const pad=size==="sm"?"6px 14px":size==="lg"?"14px 28px":"10px 20px";const fs=size==="sm"?13:size==="lg"?16:14;return<button disabled={disabled} onClick={onClick} style={{display:"inline-flex",alignItems:"center",gap:8,justifyContent:"center",padding:pad,fontSize:fs,fontWeight:600,borderRadius:10,border:"none",background:disabled?"#CBD5E1":color,color:disabled?"#94A3B8":textColor,cursor:disabled?"not-allowed":"pointer",width:full?"100%":"auto",opacity:disabled?0.6:1,transition:"all 0.2s",...extra}} onMouseEnter={e=>{if(!disabled)e.currentTarget.style.opacity="0.85";}} onMouseLeave={e=>{e.currentTarget.style.opacity=disabled?"0.6":"1";}}>{icon&&<Icon name={icon} size={fs} color={textColor}/>}{children}</button>;}
function Input({label,value,onChange,type="text",placeholder,required,disabled,options,style:extra={}}){const base={width:"100%",padding:"10px 14px",borderRadius:10,border:`1px solid ${C.border}`,fontSize:14,color:C.text,background:disabled?C.grayLight:C.white,outline:"none",boxSizing:"border-box",...extra};return<div style={{marginBottom:16}}>{label&&<label style={{display:"block",fontSize:13,fontWeight:600,color:C.textLight,marginBottom:6}}>{label}{required&&<span style={{color:C.red}}> *</span>}</label>}{type==="select"?<select value={value} onChange={e=>onChange(e.target.value)} style={{...base,cursor:"pointer"}} disabled={disabled}>{options?.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</select>:type==="textarea"?<textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} style={{...base,minHeight:80,resize:"vertical"}} disabled={disabled}/>:<input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} required={required} disabled={disabled} style={base} onFocus={e=>{e.target.style.borderColor=C.red;e.target.style.boxShadow=`0 0 0 3px ${C.red}22`;}} onBlur={e=>{e.target.style.borderColor=C.border;e.target.style.boxShadow="none";}}/>}</div>;}
function KpiCard({icon,label,value,color}){return<Card style={{textAlign:"center",flex:1,minWidth:130}}><div style={{width:36,height:36,borderRadius:10,background:color+"15",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 6px"}}><Icon name={icon} size={18} color={color}/></div><div style={{fontSize:26,fontWeight:800,color}}>{value}</div><div style={{fontSize:11,color:C.textLight,marginTop:2}}>{label}</div></Card>;}
function Table({columns,data,rowStyle}){if(!data||!data.length)return<div style={{padding:32,textAlign:"center",color:C.textLight,fontSize:14}}>Sin registros</div>;return<div style={{overflowX:"auto"}}><table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}><thead><tr>{columns.map((c,i)=><th key={i} style={{textAlign:"left",padding:"10px 12px",borderBottom:`2px solid ${C.border}`,color:C.textLight,fontWeight:600,fontSize:12,textTransform:"uppercase",letterSpacing:"0.05em",whiteSpace:"nowrap"}}>{c.label}</th>)}</tr></thead><tbody>{data.map((row,ri)=><tr key={ri} style={{borderBottom:`1px solid ${C.grayLight}`,...(rowStyle?rowStyle(row):{})}} onMouseEnter={e=>e.currentTarget.style.background=C.grayBg} onMouseLeave={e=>e.currentTarget.style.background=rowStyle?.(row)?.background||"transparent"}>{columns.map((c,ci)=><td key={ci} style={{padding:"10px 12px",color:C.text}}>{c.render?c.render(row,ri):row[c.key]}</td>)}</tr>)}</tbody></table></div>;}
function Logo({size="lg"}){const s=size==="sm"?36:52;return<div style={{display:"flex",alignItems:"center",gap:size==="sm"?10:14}}><div style={{width:s,height:s,borderRadius:s*0.22,background:C.red,display:"flex",alignItems:"center",justifyContent:"center"}}><span style={{color:C.white,fontWeight:900,fontSize:s*0.52,fontFamily:"'Arial Black',Arial,sans-serif",lineHeight:1}}>R</span></div><div><div style={{fontSize:size==="sm"?18:26,fontWeight:800,color:C.red,lineHeight:1.1,letterSpacing:"-0.02em"}}>REGISTRO</div><div style={{fontSize:size==="sm"?10:13,fontWeight:500,color:C.gray,letterSpacing:"0.2em",lineHeight:1.2}}>GESTIÓN</div></div></div>;}

// MAIN APP
export default function App(){
  const[data,setData]=useState(()=>createDemoData());
  const[screen,setScreen]=useState("legal");
  const[currentUser,setCurrentUser]=useState(null);
  const[activeTab,setActiveTab]=useState("dashboard");
  const[modal,setModal]=useState(null);
  const[now,setNow]=useState(new Date());
  const[toast,setToast]=useState(null);

  useEffect(()=>{const t=setInterval(()=>setNow(new Date()),1000);return()=>clearInterval(t);},[]);
  const showToast=useCallback((msg,type="success")=>{setToast({msg,type});setTimeout(()=>setToast(null),3000);},[]);
  const updateData=useCallback(fn=>{setData(prev=>{const next=JSON.parse(JSON.stringify(prev));fn(next);return next;});},[]);

  const getUserName=useCallback(id=>data.users.find(u=>u.id===id)?.name||"—",[data.users]);
  const getManagedUsers=useCallback(()=>{if(!currentUser)return[];if(currentUser.role==="admin")return data.users.filter(u=>u.role!=="admin");if(currentUser.role==="responsable")return data.users.filter(u=>u.responsableId===currentUser.id||u.id===currentUser.id);return[currentUser];},[currentUser,data.users]);
  const getUserIncDays=useCallback((uid,tid)=>{const uc=data.userConfig[uid]?.incidencias?.[tid];if(uc!==undefined&&uc.dias!==undefined&&uc.dias!==null&&uc.dias!=="")return uc.dias;return data.config.incidencias[tid]?.diasDefecto??0;},[data.userConfig,data.config.incidencias]);
  const getUserHorasRatio=useCallback(uid=>data.userConfig[uid]?.horasExtraPorDia??data.config.horasExtraPorDia,[data.userConfig,data.config.horasExtraPorDia]);
  const getUsedDaysByType=useCallback((uid,tid)=>data.solicitudes.filter(s=>s.userId===uid&&s.type===tid&&s.status==="aprobada").reduce((sum,s)=>sum+calcBizDays(s.dateFrom,s.dateTo),0),[data.solicitudes]);
  const getVacUsed=useCallback((uid,yr)=>data.solicitudes.filter(s=>s.userId===uid&&s.type==="vacaciones"&&s.vacYear===yr&&s.status==="aprobada").reduce((sum,s)=>sum+calcBizDays(s.dateFrom,s.dateTo),0),[data.solicitudes]);
  const getVacPending=useCallback((uid,yr)=>data.solicitudes.filter(s=>s.userId===uid&&s.type==="vacaciones"&&s.vacYear===yr&&s.status==="pendiente").reduce((sum,s)=>sum+calcBizDays(s.dateFrom,s.dateTo),0),[data.solicitudes]);
  const getHorasAcum=useCallback(uid=>data.horasExtra.filter(h=>h.userId===uid).reduce((s,h)=>s+h.horas,0),[data.horasExtra]);
  const getCompDias=useCallback(uid=>data.compensaciones.filter(c=>c.userId===uid).reduce((s,c)=>s+c.dias,0),[data.compensaciones]);

  const todayFichajes=useMemo(()=>{if(!currentUser)return[];return data.fichajes.filter(f=>f.userId===currentUser.id&&f.date===todayStr()).sort((a,b)=>new Date(a.serverTime)-new Date(b.serverTime));},[data.fichajes,currentUser,now]);
  const clockStatus=useMemo(()=>{if(!todayFichajes.length)return"none";const l=todayFichajes[todayFichajes.length-1];if(l.type==="entrada"||l.type==="fin_pausa")return"working";if(l.type==="pausa_cafe"||l.type==="pausa_comida")return"paused";if(l.type==="salida")return"done";return"none";},[todayFichajes]);
  const todayWorkedMs=useMemo(()=>{let t=0,ws=null;for(const f of todayFichajes){if(f.type==="entrada"||f.type==="fin_pausa")ws=new Date(f.serverTime);else if((f.type==="pausa_cafe"||f.type==="pausa_comida"||f.type==="salida")&&ws){t+=new Date(f.serverTime)-ws;ws=null;}}if(ws&&clockStatus==="working")t+=now-ws;return t;},[todayFichajes,clockStatus,now]);
  const todayWorkedStr=useMemo(()=>{const s=Math.floor(todayWorkedMs/1000);return`${String(Math.floor(s/3600)).padStart(2,"0")}:${String(Math.floor((s%3600)/60)).padStart(2,"0")}:${String(s%60).padStart(2,"0")}`;},[todayWorkedMs]);

  function handleLogin(email,pw){
    const user=data.users.find(u=>u.email===email);
    const log={id:uid(),userId:user?.id||null,email,success:false,reason:"",timestamp:new Date().toISOString(),platform:detectPlatform(),ua:navigator.userAgent.slice(0,120),res:getScreenRes(),ip:"192.168.1."+Math.floor(Math.random()*254+1)};
    if(!user){log.reason="Credenciales inválidas";updateData(d=>d.accessLogs.unshift(log));return"Credenciales incorrectas.";}
    if(!user.active){log.reason="Cuenta desactivada";log.userId=user.id;updateData(d=>d.accessLogs.unshift(log));return"Cuenta desactivada.";}
    if(user.password!==hashPw(pw)){log.reason="Credenciales inválidas";log.userId=user.id;updateData(d=>d.accessLogs.unshift(log));return"Credenciales incorrectas.";}
    log.success=true;log.userId=user.id;updateData(d=>d.accessLogs.unshift(log));setCurrentUser(user);
    const unread=data.mensajes.filter(m=>m.active&&m.targetUsers.includes(user.id)&&!m.readBy.includes(user.id));
    if(unread.length>0)setScreen("messageWall");else{setScreen("app");setActiveTab(TABS_BY_ROLE[user.role][0]);}return null;
  }
  function doFichar(type){const t=new Date();updateData(d=>{d.fichajes.push({id:uid(),userId:currentUser.id,date:todayStr(),type,userTime:t.toISOString(),serverTime:t.toISOString(),timeDiff:Math.floor(Math.random()*500)});});}
  function handleLogout(){setCurrentUser(null);setScreen("legal");setModal(null);}

  const unreadMessages=useMemo(()=>{if(!currentUser)return[];return data.mensajes.filter(m=>m.active&&m.targetUsers.includes(currentUser.id)&&!m.readBy.includes(currentUser.id));},[data.mensajes,currentUser]);
  function markRead(mid){updateData(d=>{const m=d.mensajes.find(x=>x.id===mid);if(m&&!m.readBy.includes(currentUser.id))m.readBy.push(currentUser.id);});setTimeout(()=>{const s=data.mensajes.filter(m=>m.active&&m.targetUsers.includes(currentUser.id)&&!m.readBy.includes(currentUser.id)&&m.id!==mid);if(!s.length){setScreen("app");setActiveTab(TABS_BY_ROLE[currentUser.role][0]);}},100);}

  // SCREENS
  if(screen==="legal")return<div style={{minHeight:"100vh",background:`linear-gradient(135deg,${C.grayBg},#EEF2FF)`,display:"flex",alignItems:"center",justifyContent:"center",padding:20,fontFamily:"'Inter',system-ui,sans-serif"}}><div style={{background:C.white,borderRadius:20,maxWidth:640,width:"100%",boxShadow:"0 25px 60px rgba(0,0,0,0.08)",overflow:"hidden"}}><div style={{background:C.red,padding:"28px 40px",textAlign:"center"}}><Logo/><div style={{color:"rgba(255,255,255,0.85)",fontSize:13,marginTop:8,fontStyle:"italic"}}>Tus trámites en línea</div></div><div style={{padding:"32px 40px"}}><h2 style={{fontSize:20,fontWeight:700,color:C.text,marginBottom:20,display:"flex",alignItems:"center",gap:10}}><Icon name="shield" size={22} color={C.red}/>Aviso Legal y Protección de Datos</h2><div style={{fontSize:13,lineHeight:1.8,color:C.text,maxHeight:300,overflowY:"auto",paddingRight:8}}><p style={{marginTop:0}}><strong>Registro de jornada laboral</strong></p><p>En cumplimiento del <strong>RDL 8/2019</strong> y <strong>art. 34.9 ET</strong>, se implementa este sistema de registro horario digital.</p><p>Datos tratados conforme al <strong>RGPD (UE) 2016/679</strong> y <strong>LOPDGDD (LO 3/2018)</strong>.</p><ul style={{paddingLeft:20}}><li><strong>Base jurídica:</strong> art. 6.1.c RGPD.</li><li><strong>Conservación:</strong> 4 años mínimo.</li><li><strong>Derechos ARCO+</strong> ejercitables ante el DPD.</li></ul></div><div style={{marginTop:24}}><Btn full size="lg" onClick={()=>setScreen("login")} icon="check">Acepto — Acceder al sistema</Btn></div></div></div></div>;

  if(screen==="login")return<LoginScreen onLogin={handleLogin}/>;

  if(screen==="messageWall"){const msg=unreadMessages[0];if(!msg){setScreen("app");return null;}return<div style={{minHeight:"100vh",background:`linear-gradient(135deg,${C.grayBg},#EEF2FF)`,display:"flex",alignItems:"center",justifyContent:"center",padding:20,fontFamily:"'Inter',system-ui,sans-serif"}}><div style={{background:C.white,borderRadius:20,maxWidth:560,width:"100%",boxShadow:"0 25px 60px rgba(0,0,0,0.08)",overflow:"hidden"}}><div style={{background:C.amber,padding:"20px 32px",display:"flex",alignItems:"center",gap:12}}><Icon name="bell" size={24} color={C.white}/><div><div style={{color:C.white,fontWeight:700,fontSize:16}}>Mensaje obligatorio</div><div style={{color:"rgba(255,255,255,0.8)",fontSize:12}}>{unreadMessages.length} pendiente(s)</div></div></div><div style={{padding:32}}><h3 style={{fontSize:18,fontWeight:700,color:C.text,marginTop:0}}>{msg.title}</h3><p style={{fontSize:14,lineHeight:1.7}}>{msg.body}</p><div style={{fontSize:12,color:C.textLight,marginBottom:20}}>Por: {getUserName(msg.authorId)}</div><Btn full onClick={()=>markRead(msg.id)} icon="check" color={C.green}>Marcar como leído</Btn></div></div></div>;}

  const tabs=TABS_BY_ROLE[currentUser?.role]||[];const half=Math.ceil(tabs.length/2);const row1=tabs.slice(0,half);const row2=tabs.slice(half);
  const cp={data,currentUser,updateData,setModal,showToast,modal,getUserName,getManagedUsers,getUserIncDays,getUserHorasRatio,getUsedDaysByType,getVacUsed,getVacPending,getHorasAcum,getCompDias};

  return(
    <div style={{minHeight:"100vh",background:C.grayBg,fontFamily:"'Inter',system-ui,-apple-system,sans-serif"}}>
      {toast&&<div style={{position:"fixed",top:20,right:20,zIndex:2000,padding:"12px 24px",borderRadius:12,fontWeight:600,fontSize:14,color:C.white,background:toast.type==="error"?C.danger:C.green,boxShadow:"0 8px 24px rgba(0,0,0,0.15)",animation:"slideIn 0.3s"}}>{toast.msg}</div>}
      <nav style={{position:"sticky",top:0,zIndex:100,background:C.white,borderBottom:`1px solid ${C.border}`,boxShadow:"0 1px 4px rgba(0,0,0,0.04)"}}>
        <div style={{maxWidth:1280,margin:"0 auto",padding:"0 16px"}}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",height:52}}>
            <Logo size="sm"/>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <span style={{fontSize:13,color:C.textLight,maxWidth:140,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{currentUser?.name}</span>
              <Badge text={currentUser?.role} type={currentUser?.role}/>
              <button onClick={handleLogout} style={{background:"none",border:"none",cursor:"pointer",padding:6}} title="Salir"><Icon name="logout" size={18} color={C.textLight}/></button>
            </div>
          </div>
          {[row1,row2].map((row,ri)=>row.length>0&&<div key={ri} style={{display:"flex",gap:1,justifyContent:"center",borderTop:ri>0?`1px solid ${C.grayLight}`:"none"}}>
            {row.map(t=>{const m=TAB_META[t];const a=activeTab===t;return<button key={t} onClick={()=>setActiveTab(t)} title={m.label} style={{display:"flex",alignItems:"center",gap:5,padding:"7px 11px",fontSize:12,fontWeight:a?700:500,color:a?C.red:C.textLight,background:a?C.redBg:"transparent",border:"none",borderBottom:a?`2px solid ${C.red}`:"2px solid transparent",cursor:"pointer",whiteSpace:"nowrap",borderRadius:"6px 6px 0 0",transition:"all 0.15s"}}><Icon name={m.icon} size={14} color={a?C.red:C.textLight}/><span>{m.label}</span></button>;})}
          </div>)}
        </div>
      </nav>
      <main style={{maxWidth:1280,margin:"0 auto",padding:"24px 16px"}}>
        {activeTab==="fichar"&&<TabFichar {...{clockStatus,todayFichajes,todayWorkedStr,now,doFichar}}/>}
        {activeTab==="vacaciones"&&<TabVacaciones {...cp}/>}
        {activeTab==="solicitudes"&&<TabSolicitudes {...cp}/>}
        {activeTab==="documentos"&&<TabDocumentos {...cp}/>}
        {activeTab==="dashboard"&&<TabDashboard {...cp}/>}
        {activeTab==="aprobar"&&<TabAprobar {...cp}/>}
        {activeTab==="plan"&&<TabPlan {...cp}/>}
        {activeTab==="horas"&&<TabHoras {...cp}/>}
        {activeTab==="mensajes"&&<TabMensajes {...cp}/>}
        {activeTab==="usuarios"&&<TabUsuarios {...cp}/>}
        {activeTab==="config"&&<TabConfig {...cp}/>}
        {activeTab==="calendario"&&<TabCalendario {...cp}/>}
        {activeTab==="datos"&&<TabDatos {...cp}/>}
        {activeTab==="accesos"&&<TabAccesos {...cp}/>}
      </main>
      <style>{`@keyframes slideIn{from{transform:translateX(80px);opacity:0}to{transform:translateX(0);opacity:1}}*{box-sizing:border-box}body{margin:0}::-webkit-scrollbar{width:6px;height:6px}::-webkit-scrollbar-thumb{background:#CBD5E1;border-radius:3px}`}</style>
    </div>
  );
}

function LoginScreen({onLogin}){const[email,setEmail]=useState("");const[pw,setPw]=useState("");const[err,setErr]=useState("");const[showPw,setShowPw]=useState(false);const submit=()=>{if(!email||!pw){setErr("Complete todos los campos.");return;}const r=onLogin(email,pw);if(r)setErr(r);};return<div style={{minHeight:"100vh",background:`linear-gradient(135deg,${C.grayBg},#EEF2FF)`,display:"flex",alignItems:"center",justifyContent:"center",padding:20,fontFamily:"'Inter',system-ui,sans-serif"}}><div style={{background:C.white,borderRadius:20,maxWidth:420,width:"100%",boxShadow:"0 25px 60px rgba(0,0,0,0.08)",overflow:"hidden"}}><div style={{padding:"32px 40px 20px",textAlign:"center",borderBottom:`1px solid ${C.grayLight}`}}><Logo/><div style={{color:C.textLight,fontSize:13,marginTop:10,fontStyle:"italic"}}>Tus trámites en línea</div></div><div style={{padding:"28px 40px 36px"}}><h2 style={{fontSize:20,fontWeight:700,color:C.text,marginTop:0,marginBottom:20,textAlign:"center"}}>Iniciar sesión</h2>{err&&<div style={{background:C.redLight,color:"#991B1B",padding:"10px 16px",borderRadius:10,fontSize:13,marginBottom:16,display:"flex",alignItems:"center",gap:8}}><Icon name="alert" size={16} color="#991B1B"/>{err}</div>}<Input label="Email" value={email} onChange={setEmail} type="email" placeholder="correo@registro.es"/><div style={{position:"relative"}}><Input label="Contraseña" value={pw} onChange={setPw} type={showPw?"text":"password"} placeholder="Contraseña"/><button onClick={()=>setShowPw(!showPw)} style={{position:"absolute",right:12,top:34,background:"none",border:"none",cursor:"pointer"}}><Icon name="eye" size={16} color={C.textLight}/></button></div><div style={{marginTop:8}}><Btn full size="lg" onClick={submit} icon="login">Acceder</Btn></div><div style={{marginTop:16,padding:14,background:C.grayBg,borderRadius:10,fontSize:11,color:C.textLight,lineHeight:1.6}}><strong>Demo:</strong> admin@registro.es / admin123 | maria.garcia@registro.es / resp123 | carlos.lopez@registro.es / user123</div></div></div></div>;}

// FICHAR
function TabFichar({clockStatus,todayFichajes,todayWorkedStr,now,doFichar}){const sm={none:{l:"Sin fichar",c:C.gray,bg:C.grayLight},working:{l:"Trabajando",c:"#065F46",bg:C.greenLight},paused:{l:"En pausa",c:"#92400E",bg:C.amberLight},done:{l:"Jornada finalizada",c:"#5B21B6",bg:C.purpleLight}};const st=sm[clockStatus];const tl={entrada:"Entrada",pausa_cafe:"Pausa café",pausa_comida:"Pausa comida",fin_pausa:"Fin pausa",salida:"Salida"};const tb={entrada:"ok",pausa_cafe:"pendiente",pausa_comida:"pendiente",fin_pausa:"info",salida:"rechazada"};return<div style={{maxWidth:600,margin:"0 auto"}}><Card style={{textAlign:"center",marginBottom:20}}><div style={{marginBottom:16}}><span style={{display:"inline-block",padding:"6px 20px",borderRadius:999,background:st.bg,color:st.c,fontWeight:700,fontSize:14}}>{st.l}</span></div><div style={{fontSize:56,fontWeight:800,color:C.text,fontVariantNumeric:"tabular-nums",lineHeight:1}}>{now.toLocaleTimeString("es-ES",{hour:"2-digit",minute:"2-digit",second:"2-digit"})}</div><div style={{fontSize:14,color:C.textLight,marginTop:8}}>{fullDateStr(now)}</div><div style={{marginTop:16,fontSize:13,color:C.textLight}}>Trabajado: <strong style={{color:C.text,fontSize:18}}>{todayWorkedStr}</strong></div></Card><div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:20}}><Btn full size="lg" color={C.green} disabled={clockStatus!=="none"} onClick={()=>doFichar("entrada")} icon="play">Entrada</Btn><div style={{display:"flex",gap:10}}><Btn full color={C.amber} disabled={clockStatus!=="working"} onClick={()=>doFichar("pausa_cafe")} icon="coffee" style={{flex:1}}>Café</Btn><Btn full color={C.amber} disabled={clockStatus!=="working"} onClick={()=>doFichar("pausa_comida")} icon="utensils" style={{flex:1}}>Comida</Btn></div><Btn full size="lg" color={C.red} disabled={clockStatus!=="paused"} onClick={()=>doFichar("fin_pausa")} icon="play">Fin pausa</Btn><Btn full size="lg" color="#7C3AED" disabled={clockStatus!=="working"} onClick={()=>doFichar("salida")} icon="square">Salida</Btn></div>{todayFichajes.length>0&&<Card><h3 style={{fontSize:15,fontWeight:700,color:C.text,marginTop:0,marginBottom:12}}><Icon name="clock" size={16} color={C.red}/> Registro de hoy</h3><Table columns={[{label:"Tipo",render:r=><Badge text={tl[r.type]} type={tb[r.type]}/>},{label:"Hora",render:r=>fmtTime(r.serverTime)},{label:"Valid.",render:r=>r.timeDiff>2000?<span style={{color:C.danger,fontWeight:700,fontSize:12}}>Dif:{(r.timeDiff/1000).toFixed(1)}s</span>:<span style={{color:C.green,fontSize:12}}>OK</span>}]} data={todayFichajes}/></Card>}</div>;}

// VACACIONES
function TabVacaciones({data,currentUser,getVacUsed,getVacPending,getHorasAcum,getCompDias,getUserHorasRatio,updateData,setModal,showToast,modal}){const[selY,setSelY]=useState(null);const pools=data.vacPools[currentUser.id]||{};const years=Object.keys(pools).map(Number).sort((a,b)=>b-a);const ratio=getUserHorasRatio(currentUser.id);const ha=getHorasAcum(currentUser.id);const dg=ratio>0?ha/ratio:0;const dc=getCompDias(currentUser.id);const actY=years.filter(y=>pools[y]?.active);const mySol=data.solicitudes.filter(s=>s.userId===currentUser.id&&s.type==="vacaciones"&&(selY===null||s.vacYear===selY)).sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt));function sub(f){const biz=calcBizDays(f.df,f.dt);const p=pools[f.vy];if(!p||!p.active){showToast("Pool no activo","error");return;}const d=p.total-getVacUsed(currentUser.id,f.vy)-getVacPending(currentUser.id,f.vy);if(biz>d){showToast(`Solo ${d} días disponibles`,"error");return;}updateData(x=>{x.solicitudes.push({id:uid(),userId:currentUser.id,type:"vacaciones",vacYear:f.vy,dateFrom:f.df,dateTo:f.dt,description:f.desc,status:"pendiente",createdAt:new Date().toISOString(),reviewedBy:null,reviewedAt:null});});setModal(null);showToast("Solicitud enviada");}
  return<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:0}}>Mis vacaciones</h2><Btn onClick={()=>setModal("nv")} icon="plus" size="sm">Solicitar</Btn></div><div style={{display:"flex",gap:12,flexWrap:"wrap",marginBottom:20}}>{years.map(y=>{const p=pools[y];const u=getVacUsed(currentUser.id,y);const pe=getVacPending(currentUser.id,y);const d=p.total-u-pe;const sel=selY===y;return<Card key={y} onClick={()=>setSelY(sel?null:y)} style={{flex:"1 1 200px",maxWidth:260,opacity:p.active?1:0.5,border:sel?`2px solid ${C.red}`:`1px solid ${C.border}`,position:"relative"}}>{!p.active&&<div style={{position:"absolute",top:8,right:8}}><Icon name="lock" size={16} color={C.textLight}/></div>}<div style={{fontSize:20,fontWeight:800}}>{y}</div><div style={{fontSize:12,color:C.textLight,marginTop:4}}>{p.total} días</div><div style={{display:"flex",gap:16,marginTop:10,fontSize:12}}><span><strong style={{color:C.green}}>{u}</strong> usados</span><span><strong style={{color:C.amber}}>{pe}</strong> pend.</span><span><strong style={{color:C.blue}}>{d}</strong> disp.</span></div><div style={{marginTop:10,height:6,borderRadius:3,background:C.grayLight,overflow:"hidden"}}><div style={{height:"100%",width:`${Math.min(p.total>0?(u/p.total)*100:0,100)}%`,borderRadius:3,background:`linear-gradient(90deg,${C.green},${C.amber})`}}/></div></Card>;})}</div><Card style={{marginBottom:20,background:"linear-gradient(135deg,#FFFBEB,#FEF3C7)",border:`1px solid ${C.amberLight}`}}><h3 style={{fontSize:14,fontWeight:700,color:"#92400E",margin:"0 0 8px"}}><Icon name="plus" size={16} color="#92400E"/> Horas extra</h3><div style={{display:"flex",gap:20,flexWrap:"wrap",fontSize:13}}><div>Acumuladas: <strong>{ha}h</strong></div><div>Generados: <strong>{dg.toFixed(1)}d</strong></div><div>Compensados: <strong>{dc}d</strong></div><div>Disponibles: <strong style={{color:C.green}}>{Math.max(0,dg-dc).toFixed(1)}d</strong></div><div>Ratio: <strong>{ratio}h=1d</strong></div></div></Card><Card><h3 style={{fontSize:14,fontWeight:700,margin:"0 0 12px"}}>{selY?`Solicitudes ${selY}`:"Todas"}</h3><Table columns={[{label:"Año",render:r=>r.vacYear?<Badge text={r.vacYear} type="purple"/>:"—"},{label:"Desde",render:r=>fmtDate(r.dateFrom)},{label:"Hasta",render:r=>fmtDate(r.dateTo)},{label:"Días",render:r=>calcBizDays(r.dateFrom,r.dateTo)},{label:"Estado",render:r=><Badge text={r.status} type={r.status}/>},{label:"Desc.",key:"description"}]} data={mySol}/></Card>{modal==="nv"&&<Modal title="Solicitar vacaciones" onClose={()=>setModal(null)}><VF ay={actY} pools={pools} cu={currentUser} gvu={getVacUsed} gvp={getVacPending} onS={sub}/></Modal>}</div>;}
function VF({ay,pools,cu,gvu,gvp,onS}){const[vy,setVy]=useState(ay[0]||CURRENT_YEAR);const[df,setDf]=useState("");const[dt,setDt]=useState("");const[desc,setDesc]=useState("");const biz=calcBizDays(df,dt);const yo=ay.map(y=>{const p=pools[y];return{value:y,label:`${y} — ${p.total-gvu(cu.id,y)-gvp(cu.id,y)} disp.`};});return<><Input label="Año" type="select" value={vy} onChange={v=>setVy(Number(v))} options={yo}/><Input label="Desde" type="date" value={df} onChange={setDf}/><Input label="Hasta" type="date" value={dt} onChange={setDt}/>{biz>0&&<div style={{fontSize:13,color:C.textLight,marginBottom:12}}>Días: <strong>{biz}</strong></div>}<Input label="Notas" type="textarea" value={desc} onChange={setDesc} placeholder="Opcional"/><Btn full onClick={()=>onS({vy,df,dt,desc})} icon="send" disabled={!df||!dt||biz<=0}>Enviar</Btn></>;}

// SOLICITUDES
function TabSolicitudes({data,currentUser,getUserIncDays,getUsedDaysByType,updateData,setModal,showToast,modal}){const tipos=Object.entries(data.config.incidencias).filter(([k,v])=>v.activo&&k!=="vacaciones");const mySol=data.solicitudes.filter(s=>s.userId===currentUser.id&&s.type!=="vacaciones").sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt));function sub(f){const d=getUserIncDays(currentUser.id,f.type);const biz=calcBizDays(f.df,f.dt);if(d>0){const u=getUsedDaysByType(currentUser.id,f.type);if(u+biz>d){showToast(`Solo quedan ${d-u} días`,"error");return;}}if(f.type==="otros"&&!f.desc){showToast("Descripción obligatoria","error");return;}updateData(x=>{x.solicitudes.push({id:uid(),userId:currentUser.id,type:f.type,vacYear:null,dateFrom:f.df,dateTo:f.dt,description:f.desc,status:"pendiente",createdAt:new Date().toISOString(),reviewedBy:null,reviewedAt:null});});setModal(null);showToast("Solicitud enviada");}return<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:0}}>Solicitudes</h2><Btn onClick={()=>setModal("ns")} icon="plus" size="sm">Nueva</Btn></div><Card><Table columns={[{label:"Tipo",render:r=><Badge text={data.config.incidencias[r.type]?.label||r.type} type="info"/>},{label:"Desde",render:r=>fmtDate(r.dateFrom)},{label:"Hasta",render:r=>fmtDate(r.dateTo)},{label:"Días",render:r=>calcBizDays(r.dateFrom,r.dateTo)},{label:"Estado",render:r=><Badge text={r.status} type={r.status}/>}]} data={mySol}/></Card>{modal==="ns"&&<Modal title="Nueva solicitud" onClose={()=>setModal(null)}><SF tipos={tipos} cu={currentUser} gi={getUserIncDays} gu={getUsedDaysByType} onS={sub}/></Modal>}</div>;}
function SF({tipos,cu,gi,gu,onS}){const[type,setType]=useState(tipos[0]?.[0]||"");const[df,setDf]=useState("");const[dt,setDt]=useState("");const[desc,setDesc]=useState("");const biz=calcBizDays(df,dt);const opts=tipos.map(([k,v])=>{const d=gi(cu.id,k);const u=gu(cu.id,k);return{value:k,label:`${v.label} ${d>0?`(${Math.max(0,d-u)}/${d})`:"(ilim.)"}`};});return<><Input label="Tipo" type="select" value={type} onChange={setType} options={opts}/><Input label="Desde" type="date" value={df} onChange={setDf}/><Input label="Hasta" type="date" value={dt} onChange={setDt}/>{biz>0&&<div style={{fontSize:13,color:C.textLight,marginBottom:12}}>Días: <strong>{biz}</strong></div>}<Input label="Descripción" type="textarea" value={desc} onChange={setDesc}/><Btn full onClick={()=>onS({type,df,dt,desc})} icon="send" disabled={!df||!dt||biz<=0}>Enviar</Btn></>;}

// DOCUMENTOS
function TabDocumentos({data,currentUser,updateData,setModal,showToast,modal}){const docs=data.documentos.filter(d=>d.userId===currentUser.id).sort((a,b)=>new Date(b.uploadedAt)-new Date(a.uploadedAt));const[desc,setDesc]=useState("");const[fn,setFn]=useState("");function up(){if(!fn){showToast("Seleccione archivo","error");return;}updateData(d=>{d.documentos.push({id:uid(),userId:currentUser.id,fileName:fn,fileSize:Math.floor(Math.random()*5000+100)+"KB",description:desc,uploadedAt:new Date().toISOString()});});setModal(null);setDesc("");setFn("");showToast("Subido");}return<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:0}}>Documentos</h2><Btn onClick={()=>setModal("nd")} icon="upload" size="sm">Subir</Btn></div><Card><Table columns={[{label:"Archivo",render:r=><span style={{display:"flex",alignItems:"center",gap:6}}><Icon name="filetext" size={14} color={C.blue}/>{r.fileName}</span>},{label:"Descripción",key:"description"},{label:"Fecha",render:r=>fmtDateTime(r.uploadedAt)}]} data={docs}/></Card>{modal==="nd"&&<Modal title="Subir documento" onClose={()=>setModal(null)}><Input label="Descripción" value={desc} onChange={setDesc}/><div style={{marginBottom:16}}><label style={{display:"block",fontSize:13,fontWeight:600,color:C.textLight,marginBottom:6}}>Archivo</label><input type="file" accept=".pdf,.jpg,.png,.doc,.docx" onChange={e=>setFn(e.target.files?.[0]?.name||"")} style={{fontSize:13}}/></div><Btn full onClick={up} icon="upload" disabled={!fn}>Subir</Btn></Modal>}</div>;}

// DASHBOARD - MULTI CHART
function TabDashboard({data,getManagedUsers}){const managed=getManagedUsers();const[selU,setSelU]=useState("all");const[selM,setSelM]=useState(new Date().getMonth());const[ct,setCt]=useState("barH");const filtered=selU==="all"?managed:managed.filter(u=>u.id===selU);
  const stats=useMemo(()=>filtered.map(u=>{const uf=data.fichajes.filter(f=>f.userId===u.id&&new Date(f.serverTime).getMonth()===selM);const days=new Set(uf.map(f=>f.date));let ms=0;for(const day of days){const df=uf.filter(f=>f.date===day).sort((a,b)=>new Date(a.serverTime)-new Date(b.serverTime));let ws=null;for(const f of df){if(f.type==="entrada"||f.type==="fin_pausa")ws=new Date(f.serverTime);else if((f.type==="pausa_cafe"||f.type==="pausa_comida"||f.type==="salida")&&ws){ms+=new Date(f.serverTime)-ws;ws=null;}}}const h=ms/3600000;return{id:u.id,name:u.name,hours:Math.round(h*10)/10,days:days.size,avg:days.size>0?(h/days.size).toFixed(1):"0"};}),[filtered,data.fichajes,selM]);
  const tH=stats.reduce((s,u)=>s+u.hours,0);const tD=stats.reduce((s,u)=>s+u.days,0);const pS=data.solicitudes.filter(s=>s.status==="pendiente"&&filtered.some(u=>u.id===s.userId)).length;const aC=filtered.filter(u=>u.active!==false).length;const mxH=Math.max(...stats.map(u=>u.hours),1);const tHA=tH||1;
  const cts=[{id:"barH",icon:"barchart",l:"Barras H"},{id:"barV",icon:"barchart",l:"Barras V"},{id:"donut",icon:"pie",l:"Circular"},{id:"table",icon:"list",l:"Tabla"}];
  return<div><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:"0 0 20px"}}>Dashboard</h2><div style={{display:"flex",gap:12,marginBottom:16,flexWrap:"wrap"}}><div style={{flex:1,minWidth:180}}><Input label="Empleado" type="select" value={selU} onChange={setSelU} options={[{value:"all",label:`Todos (${managed.length})`},...managed.map(u=>({value:u.id,label:u.name}))]}/></div><div style={{flex:1,minWidth:180}}><Input label="Mes" type="select" value={selM} onChange={v=>setSelM(Number(v))} options={MONTHS_ES.map((m,i)=>({value:i,label:m}))}/></div></div>
    <div style={{display:"flex",gap:12,flexWrap:"wrap",marginBottom:20}}><KpiCard icon="clock" label="Horas totales" value={tH.toFixed(1)} color={C.blue}/><KpiCard icon="calendar" label="Días trabajados" value={tD} color={C.green}/><KpiCard icon="filetext" label="Solicitudes pend." value={pS} color={C.amber}/><KpiCard icon="users" label="Empleados activos" value={aC} color={C.purple}/></div>
    <div style={{display:"flex",gap:6,marginBottom:16}}>{cts.map(c=><button key={c.id} onClick={()=>setCt(c.id)} style={{display:"flex",alignItems:"center",gap:5,padding:"6px 14px",borderRadius:8,border:`1px solid ${ct===c.id?C.red:C.border}`,background:ct===c.id?C.redBg:C.white,color:ct===c.id?C.red:C.text,fontSize:12,fontWeight:600,cursor:"pointer"}}><Icon name={c.icon} size={14} color={ct===c.id?C.red:C.textLight}/>{c.l}</button>)}</div>
    <Card><h3 style={{fontSize:15,fontWeight:700,color:C.text,margin:"0 0 16px"}}>Horas — {MONTHS_ES[selM]}</h3>{!stats.length&&<div style={{color:C.textLight,textAlign:"center",padding:20}}>Sin datos</div>}
      {ct==="barH"&&stats.map((u,i)=><div key={u.id} style={{marginBottom:10}}><div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:3}}><span style={{fontWeight:600,maxWidth:180,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{u.name}</span><span style={{color:C.textLight}}>{u.hours}h · {u.days}d · {u.avg}h/d</span></div><div style={{height:18,borderRadius:5,background:C.grayLight,overflow:"hidden"}}><div style={{height:"100%",width:`${(u.hours/mxH)*100}%`,borderRadius:5,background:CHART_COLORS[i%30],transition:"width 0.5s"}}/></div></div>)}
      {ct==="barV"&&<div style={{display:"flex",alignItems:"flex-end",gap:3,height:260,overflowX:"auto",paddingTop:20}}>{stats.map((u,i)=>{const h=mxH>0?(u.hours/mxH)*220:0;return<div key={u.id} style={{display:"flex",flexDirection:"column",alignItems:"center",flex:"1 0 24px",minWidth:24,maxWidth:50}}><span style={{fontSize:9,fontWeight:700}}>{u.hours>0?u.hours:""}</span><div style={{width:"80%",height:h,borderRadius:"4px 4px 0 0",background:CHART_COLORS[i%30],minHeight:u.hours>0?2:0}}/><span style={{fontSize:8,color:C.textLight,marginTop:3,writingMode:"vertical-rl",maxHeight:50,overflow:"hidden"}}>{u.name.split(" ")[0]}</span></div>;})}</div>}
      {ct==="donut"&&(()=>{const sz=200,cx=sz/2,cy=sz/2,r=75,r2=50;let cum=0;const sl=stats.filter(u=>u.hours>0).map((u,i)=>{const pct=u.hours/tHA;const ang=pct*360;const sa=cum;cum+=ang;const s1=sa*Math.PI/180,s2=(sa+ang)*Math.PI/180;const x1o=cx+r*Math.cos(s1),y1o=cy+r*Math.sin(s1),x2o=cx+r*Math.cos(s2),y2o=cy+r*Math.sin(s2),x1i=cx+r2*Math.cos(s2),y1i=cy+r2*Math.sin(s2),x2i=cx+r2*Math.cos(s1),y2i=cy+r2*Math.sin(s1);const lg=ang>180?1:0;return{path:`M${x1o},${y1o} A${r},${r} 0 ${lg} 1 ${x2o},${y2o} L${x1i},${y1i} A${r2},${r2} 0 ${lg} 0 ${x2i},${y2i} Z`,col:CHART_COLORS[i%30],name:u.name,hours:u.hours,pct};});return<div style={{display:"flex",gap:24,flexWrap:"wrap",alignItems:"center"}}><svg width={sz} height={sz} viewBox={`0 0 ${sz} ${sz}`}>{sl.map((s,i)=><path key={i} d={s.path} fill={s.col} stroke={C.white} strokeWidth="1"/>)}<text x={cx} y={cy-6} textAnchor="middle" fill={C.text} fontSize="20" fontWeight="800">{tH.toFixed(0)}</text><text x={cx} y={cy+12} textAnchor="middle" fill={C.textLight} fontSize="11">horas</text></svg><div style={{display:"flex",flexDirection:"column",gap:3,maxHeight:200,overflowY:"auto",flex:1}}>{sl.map((s,i)=><div key={i} style={{display:"flex",alignItems:"center",gap:6,fontSize:11}}><span style={{width:10,height:10,borderRadius:3,background:s.col,flexShrink:0}}/><span style={{flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{s.name}</span><strong>{s.hours}h</strong><span style={{color:C.textLight}}>({(s.pct*100).toFixed(0)}%)</span></div>)}</div></div>;})()}
      {ct==="table"&&<Table columns={[{label:"#",render:(_,i)=>i+1},{label:"Empleado",key:"name"},{label:"Horas",render:r=><strong>{r.hours}h</strong>},{label:"Días",key:"days"},{label:"h/d",key:"avg"},{label:"%",render:r=><div style={{display:"flex",alignItems:"center",gap:6}}><div style={{flex:1,height:5,borderRadius:3,background:C.grayLight,overflow:"hidden"}}><div style={{height:"100%",width:`${(r.hours/tHA)*100}%`,borderRadius:3,background:C.blue}}/></div><span style={{fontSize:11}}>{((r.hours/tHA)*100).toFixed(1)}%</span></div>}]} data={stats.sort((a,b)=>b.hours-a.hours)}/>}
    </Card></div>;}

// APROBAR
function TabAprobar({data,currentUser,getUserName,updateData,showToast,getManagedUsers}){const managed=getManagedUsers();const ids=managed.map(u=>u.id);const pending=data.solicitudes.filter(s=>s.status==="pendiente"&&ids.includes(s.userId)&&s.userId!==currentUser.id);const history=data.solicitudes.filter(s=>s.status!=="pendiente"&&s.reviewedBy&&ids.includes(s.userId)).sort((a,b)=>new Date(b.reviewedAt)-new Date(a.reviewedAt));function rev(id,st){updateData(d=>{const s=d.solicitudes.find(x=>x.id===id);if(s){s.status=st;s.reviewedBy=currentUser.id;s.reviewedAt=new Date().toISOString();}});showToast(`Solicitud ${st}`);}return<div><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:"0 0 20px"}}>Aprobar ({pending.length} pendientes)</h2>{!pending.length&&<Card style={{marginBottom:20}}><div style={{textAlign:"center",color:C.textLight,padding:16}}>Sin pendientes</div></Card>}<div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:24}}>{pending.slice(0,25).map(s=><Card key={s.id} style={{background:"#FFFBEB",border:`1px solid ${C.amberLight}`}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:8}}><div><div style={{fontWeight:700,fontSize:15}}>{getUserName(s.userId)}</div><div style={{display:"flex",gap:6,marginTop:6,flexWrap:"wrap"}}><Badge text={data.config.incidencias[s.type]?.label||s.type} type="info"/>{s.vacYear&&<Badge text={`${s.vacYear}`} type="purple"/>}</div><div style={{fontSize:13,color:C.textLight,marginTop:6}}>{fmtDate(s.dateFrom)} — {fmtDate(s.dateTo)} · {calcBizDays(s.dateFrom,s.dateTo)}d</div>{s.description&&<div style={{fontSize:13,marginTop:4}}>{s.description}</div>}</div><div style={{display:"flex",gap:8}}><Btn size="sm" color={C.green} onClick={()=>rev(s.id,"aprobada")} icon="check">Aprobar</Btn><Btn size="sm" color={C.danger} onClick={()=>rev(s.id,"rechazada")} icon="x">Rechazar</Btn></div></div></Card>)}{pending.length>25&&<div style={{textAlign:"center",color:C.textLight,fontSize:13}}>...y {pending.length-25} más</div>}</div><h3 style={{fontSize:16,fontWeight:700,marginBottom:12}}>Historial</h3><Card><Table columns={[{label:"Empleado",render:r=>getUserName(r.userId)},{label:"Tipo",render:r=><Badge text={data.config.incidencias[r.type]?.label||r.type} type="info"/>},{label:"Fechas",render:r=>`${fmtDate(r.dateFrom)} — ${fmtDate(r.dateTo)}`},{label:"Estado",render:r=><Badge text={r.status} type={r.status}/>}]} data={history.slice(0,50)}/></Card></div>;}

// PLAN VACACIONAL
function TabPlan({data,getManagedUsers,getVacUsed,getVacPending,getHorasAcum,getCompDias,getUserHorasRatio}){const managed=getManagedUsers();const[yr,setYr]=useState(CURRENT_YEAR);const[vm,setVm]=useState("year");const[sm,setSm]=useState(new Date().getMonth());const[su,setSu]=useState(managed.map(u=>u.id));const tog=id=>setSu(p=>p.includes(id)?p.filter(x=>x!==id):[...p,id]);const flt=managed.filter(u=>su.includes(u.id));
  const vmap=useMemo(()=>{const m={};flt.forEach(u=>{m[u.id]={};});data.solicitudes.filter(s=>s.type==="vacaciones"&&s.vacYear===yr&&(s.status==="aprobada"||s.status==="pendiente")&&su.includes(s.userId)).forEach(s=>{const d=new Date(s.dateFrom);const e=new Date(s.dateTo);while(d<=e){if(d.getDay()!==0&&d.getDay()!==6){const k=toISO(d);if(!m[s.userId])m[s.userId]={};m[s.userId][k]=s.status;}d.setDate(d.getDate()+1);}});return m;},[data.solicitudes,yr,su,flt]);
  const days=useMemo(()=>{let s,e;if(vm==="year"){s=new Date(yr,0,1);e=new Date(yr,11,31);}else{s=new Date(yr,sm,1);e=new Date(yr,sm+1,0);}const r=[];const d=new Date(s);while(d<=e){r.push({date:toISO(d),dow:d.getDay(),day:d.getDate(),month:d.getMonth()});d.setDate(d.getDate()+1);}return r;},[yr,vm,sm]);
  const ov=useMemo(()=>{const o={};days.forEach(d=>{const u=flt.filter(u=>vmap[u.id]?.[d.date]);if(u.length>=2)o[d.date]=u.map(x=>x.name);});return o;},[days,vmap,flt]);
  const ovC=Object.keys(ov).length;const cW=vm==="year"?3:24;const cH=22;
  return<div><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:"0 0 16px"}}>Plan Vacacional</h2><div style={{display:"flex",gap:12,marginBottom:12,flexWrap:"wrap",alignItems:"flex-end"}}><div><label style={{fontSize:12,fontWeight:600,color:C.textLight,display:"block",marginBottom:4}}>Año</label><div style={{display:"flex",gap:4}}>{[yr-1,yr,yr+1].map(y=><button key={y} onClick={()=>setYr(y)} style={{padding:"5px 14px",borderRadius:8,border:`1px solid ${y===yr?C.red:C.border}`,background:y===yr?C.red:C.white,color:y===yr?C.white:C.text,fontSize:13,fontWeight:600,cursor:"pointer"}}>{y}</button>)}</div></div><div><label style={{fontSize:12,fontWeight:600,color:C.textLight,display:"block",marginBottom:4}}>Vista</label><div style={{display:"flex",gap:4}}><button onClick={()=>setVm("year")} style={{padding:"5px 12px",borderRadius:8,border:`1px solid ${vm==="year"?C.red:C.border}`,background:vm==="year"?C.red:C.white,color:vm==="year"?C.white:C.text,fontSize:12,cursor:"pointer"}}>Año</button><select value={sm} onChange={e=>{setSm(Number(e.target.value));setVm("month");}} style={{padding:"5px 8px",borderRadius:8,border:`1px solid ${vm==="month"?C.red:C.border}`,fontSize:12,cursor:"pointer"}}>{MONTHS_ES.map((m,i)=><option key={i} value={i}>{m}</option>)}</select></div></div></div>
    <div style={{display:"flex",gap:4,flexWrap:"wrap",marginBottom:10}}><button onClick={()=>setSu(managed.map(u=>u.id))} style={{padding:"3px 10px",borderRadius:16,border:`1px solid ${C.border}`,background:su.length===managed.length?C.blue:C.white,color:su.length===managed.length?C.white:C.text,fontSize:11,cursor:"pointer",fontWeight:600}}>Todos</button>{managed.map(u=><button key={u.id} onClick={()=>tog(u.id)} style={{padding:"3px 8px",borderRadius:16,border:`1px solid ${su.includes(u.id)?C.blue:C.border}`,background:su.includes(u.id)?C.blueLight:C.white,color:su.includes(u.id)?"#1E40AF":C.text,fontSize:10,cursor:"pointer"}}>{u.name.split(" ")[0]}</button>)}</div>
    {ovC>0&&<div style={{background:C.redLight,border:`1px solid ${C.danger}`,borderRadius:10,padding:"8px 14px",marginBottom:10,fontSize:12,color:"#991B1B"}}><strong>{ovC} día(s) con solapamiento</strong></div>}
    <div style={{display:"flex",gap:10,marginBottom:8,fontSize:11,color:C.textLight}}><span style={{display:"flex",alignItems:"center",gap:4}}><span style={{width:10,height:10,borderRadius:3,background:"#BBF7D0"}}/> Aprob.</span><span style={{display:"flex",alignItems:"center",gap:4}}><span style={{width:10,height:10,borderRadius:3,background:"#FEF08A"}}/> Pend.</span><span style={{display:"flex",alignItems:"center",gap:4}}><span style={{width:10,height:10,borderRadius:3,background:"#FECACA",border:"1px solid #EF4444"}}/> Solape</span><span style={{display:"flex",alignItems:"center",gap:4}}><span style={{width:10,height:10,borderRadius:3,background:"#F1F5F9"}}/> Finde</span></div>
    <Card style={{overflow:"auto",padding:0}}><div style={{display:"flex",minWidth:"fit-content"}}><div style={{position:"sticky",left:0,background:C.white,zIndex:2,borderRight:`1px solid ${C.border}`}}><div style={{height:cH+4,borderBottom:`1px solid ${C.border}`}}/>{flt.map(u=>{const us=getVacUsed(u.id,yr);const tot=data.vacPools[u.id]?.[yr]?.total||0;return<div key={u.id} style={{height:cH,display:"flex",alignItems:"center",padding:"0 6px",fontSize:10,fontWeight:600,whiteSpace:"nowrap",borderBottom:`1px solid ${C.grayLight}`,minWidth:120}}>{u.name.split(" ").slice(0,2).join(" ")} <span style={{color:C.textLight,fontWeight:400,marginLeft:4}}>{us}/{tot}</span></div>;})}</div><div><div style={{display:"flex",height:cH+4,borderBottom:`1px solid ${C.border}`}}>{days.map((d,i)=><div key={i} style={{width:cW,minWidth:cW,textAlign:"center",fontSize:vm==="year"?0:9,color:C.textLight,display:"flex",alignItems:"flex-end",justifyContent:"center",paddingBottom:1}}>{vm!=="year"&&d.day}</div>)}</div>{flt.map(u=><div key={u.id} style={{display:"flex",height:cH,borderBottom:`1px solid ${C.grayLight}`}}>{days.map((d,i)=>{const isWe=d.dow===0||d.dow===6;const st=vmap[u.id]?.[d.date];const isOv=ov[d.date];let bg="transparent",bd="none";if(isWe)bg="#F1F5F9";else if(isOv&&st){bg="#FECACA";bd="1px solid #EF4444";}else if(st==="aprobada")bg="#BBF7D0";else if(st==="pendiente")bg="#FEF08A";return<div key={i} style={{width:cW,minWidth:cW,height:"100%",background:bg,border:bd,boxSizing:"border-box"}}/>;})}</div>)}</div></div></Card>
    <Card style={{marginTop:16}}><h3 style={{fontSize:14,fontWeight:700,margin:"0 0 10px"}}>Resumen</h3><Table columns={[{label:"Empleado",key:"name"},{label:"Total",render:r=>data.vacPools[r.id]?.[yr]?.total||0},{label:"Usados",render:r=>getVacUsed(r.id,yr)},{label:"Pend.",render:r=>getVacPending(r.id,yr)},{label:"Disp.",render:r=>{const p=data.vacPools[r.id]?.[yr];return p?p.total-getVacUsed(r.id,yr)-getVacPending(r.id,yr):0;}},{label:"%",render:r=>{const p=data.vacPools[r.id]?.[yr];if(!p||!p.total)return"—";const pct=Math.round((getVacUsed(r.id,yr)/p.total)*100);return<div style={{display:"flex",alignItems:"center",gap:6}}><div style={{flex:1,height:5,borderRadius:3,background:C.grayLight,overflow:"hidden"}}><div style={{height:"100%",width:`${pct}%`,borderRadius:3,background:C.blue}}/></div><span style={{fontSize:11}}>{pct}%</span></div>;}}]} data={flt}/></Card></div>;}

// HORAS EXTRA
function TabHoras({data,currentUser,getManagedUsers,getUserName,getUserHorasRatio,getHorasAcum,getCompDias,updateData,setModal,showToast,modal}){const m=getManagedUsers();function ah(f){updateData(d=>{d.horasExtra.push({id:uid(),userId:f.userId,fecha:f.fecha,horas:Number(f.horas),motivo:f.motivo,registradoPor:currentUser.id,createdAt:new Date().toISOString()});});setModal(null);showToast("Registrado");}function ac(f){updateData(d=>{d.compensaciones.push({id:uid(),userId:f.userId,dias:Number(f.dias),origen:f.origen,fecha:f.fecha,registradoPor:currentUser.id,createdAt:new Date().toISOString()});});setModal(null);showToast("Registrado");}return<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20,flexWrap:"wrap",gap:8}}><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:0}}>Horas Extra</h2><div style={{display:"flex",gap:8}}><Btn onClick={()=>setModal("ah")} icon="plus" size="sm">Horas</Btn><Btn onClick={()=>setModal("ac")} icon="plus" size="sm" color={C.purple}>Compensar</Btn></div></div><Card style={{marginBottom:16}}><Table columns={[{label:"Empleado",key:"name"},{label:"Horas",render:r=>getHorasAcum(r.id)+"h"},{label:"Ratio",render:r=>getUserHorasRatio(r.id)},{label:"Gen.",render:r=>{const h=getHorasAcum(r.id);const rt=getUserHorasRatio(r.id);return rt>0?(h/rt).toFixed(1):"—";}},{label:"Comp.",render:r=>getCompDias(r.id)},{label:"Disp.",render:r=>{const h=getHorasAcum(r.id);const rt=getUserHorasRatio(r.id);return rt>0?((h/rt)-getCompDias(r.id)).toFixed(1):"—";}}]} data={m}/></Card><div style={{display:"flex",gap:16,flexWrap:"wrap"}}><Card style={{flex:1,minWidth:280}}><h3 style={{fontSize:14,fontWeight:700,margin:"0 0 10px"}}>Horas extra</h3><Table columns={[{label:"Fecha",render:r=>fmtDate(r.fecha)},{label:"Empleado",render:r=>getUserName(r.userId)},{label:"Horas",render:r=>r.horas+"h"},{label:"Motivo",key:"motivo"}]} data={data.horasExtra.sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt)).slice(0,20)}/></Card><Card style={{flex:1,minWidth:280}}><h3 style={{fontSize:14,fontWeight:700,margin:"0 0 10px"}}>Compensaciones</h3><Table columns={[{label:"Fecha",render:r=>fmtDate(r.fecha)},{label:"Empleado",render:r=>getUserName(r.userId)},{label:"Días",render:r=>r.dias},{label:"Origen",key:"origen"}]} data={data.compensaciones.sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt)).slice(0,20)}/></Card></div>{modal==="ah"&&<Modal title="Registrar horas" onClose={()=>setModal(null)}><SForm fields={[{key:"userId",label:"Empleado",type:"select",options:m.map(u=>({value:u.id,label:u.name}))},{key:"horas",label:"Horas",type:"number",def:"2"},{key:"fecha",label:"Fecha",type:"date",def:todayStr()},{key:"motivo",label:"Motivo"}]} onS={ah}/></Modal>}{modal==="ac"&&<Modal title="Compensación" onClose={()=>setModal(null)}><SForm fields={[{key:"userId",label:"Empleado",type:"select",options:m.map(u=>({value:u.id,label:u.name}))},{key:"dias",label:"Días",type:"number",def:"1"},{key:"fecha",label:"Fecha",type:"date",def:todayStr()},{key:"origen",label:"Origen"}]} onS={ac} bc={C.purple}/></Modal>}</div>;}
function SForm({fields,onS,bc:btnC=C.red}){const[v,setV]=useState(()=>{const o={};fields.forEach(f=>{o[f.key]=f.def||f.options?.[0]?.value||"";});return o;});return<>{fields.map(f=><Input key={f.key} label={f.label} type={f.type||"text"} value={v[f.key]} onChange={val=>setV(p=>({...p,[f.key]:val}))} options={f.options}/>)}<Btn full onClick={()=>onS(v)} icon="check" color={btnC}>Registrar</Btn></>;}

// MENSAJES
function TabMensajes({data,currentUser,getUserName,updateData,setModal,showToast,modal}){const others=data.users.filter(u=>u.id!==currentUser.id&&u.role!=="admin");function send(f){updateData(d=>{d.mensajes.push({id:uid(),authorId:currentUser.id,title:f.title,body:f.body,targetUsers:f.targets,readBy:[],active:true,createdAt:new Date().toISOString()});});setModal(null);showToast("Enviado");}function tog(id){updateData(d=>{const m=d.mensajes.find(x=>x.id===id);if(m)m.active=!m.active;});}const my=data.mensajes.filter(m=>m.authorId===currentUser.id).sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt));return<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:0}}>Mensajes</h2><Btn onClick={()=>setModal("nm")} icon="send" size="sm">Nuevo</Btn></div>{my.map(m=><Card key={m.id} style={{marginBottom:10}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:12}}><div><div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}><span style={{fontWeight:700}}>{m.title}</span><Badge text={m.active?"Activo":"Off"} type={m.active?"activo":"inactivo"}/></div><p style={{fontSize:13,margin:"4px 0"}}>{m.body}</p><div style={{fontSize:11,color:C.textLight}}>{fmtDateTime(m.createdAt)} · {m.readBy.length}/{m.targetUsers.length} leídos</div></div><Btn size="sm" color={m.active?C.gray:C.green} onClick={()=>tog(m.id)}>{m.active?"Off":"On"}</Btn></div></Card>)}{modal==="nm"&&<Modal title="Nuevo mensaje" onClose={()=>setModal(null)}><MF others={others} onS={send}/></Modal>}</div>;}
function MF({others,onS}){const[t,setT]=useState("");const[b,setB]=useState("");const[tg,setTg]=useState([]);const tog=id=>setTg(p=>p.includes(id)?p.filter(x=>x!==id):[...p,id]);return<><Input label="Título" value={t} onChange={setT} required/><Input label="Contenido" type="textarea" value={b} onChange={setB} required/><div style={{marginBottom:16}}><label style={{display:"block",fontSize:13,fontWeight:600,color:C.textLight,marginBottom:6}}>Destinatarios</label><div style={{display:"flex",gap:4,flexWrap:"wrap"}}><button onClick={()=>setTg(others.map(u=>u.id))} style={{padding:"3px 10px",borderRadius:16,border:`1px solid ${tg.length===others.length?C.red:C.border}`,background:tg.length===others.length?C.red:C.white,color:tg.length===others.length?C.white:C.text,fontSize:11,cursor:"pointer"}}>Todos</button>{others.map(u=><button key={u.id} onClick={()=>tog(u.id)} style={{padding:"3px 8px",borderRadius:16,border:`1px solid ${tg.includes(u.id)?C.red:C.border}`,background:tg.includes(u.id)?C.redLight:C.white,color:tg.includes(u.id)?C.red:C.text,fontSize:10,cursor:"pointer"}}>{u.name.split(" ")[0]}</button>)}</div></div><Btn full onClick={()=>onS({title:t,body:b,targets:tg})} icon="send" disabled={!t||!b||!tg.length}>Enviar</Btn></>;}

// USUARIOS
function TabUsuarios({data,updateData,setModal,showToast,modal,getUserName}){const[eu,setEu]=useState(null);const resps=data.users.filter(u=>u.role==="responsable"||u.role==="admin");function sv(f){updateData(d=>{if(f.id){const u=d.users.find(x=>x.id===f.id);if(u){u.name=f.name;u.email=f.email;u.role=f.role;u.active=f.active;u.responsableId=f.resp;if(f.pw)u.password=hashPw(f.pw);}}else{const nid=uid();d.users.push({id:nid,name:f.name,email:f.email,password:hashPw(f.pw),role:f.role,active:f.active,responsableId:f.resp,createdAt:new Date().toISOString()});if(f.role!=="admin"){if(!d.vacPools[nid])d.vacPools[nid]={};d.vacPools[nid][CURRENT_YEAR]={total:22,active:true};}}});setModal(null);setEu(null);showToast(f.id?"Actualizado":"Creado");}
  const[pu,setPu]=useState(data.users[1]?.id||"");const[py,setPy]=useState(CURRENT_YEAR);const[pd,setPd]=useState("22");function ap(){updateData(d=>{if(!d.vacPools[pu])d.vacPools[pu]={};d.vacPools[pu][py]={total:Number(pd),active:true};});showToast("Pool creado");}function tp(uid,yr){updateData(d=>{if(d.vacPools[uid]?.[yr])d.vacPools[uid][yr].active=!d.vacPools[uid][yr].active;});}
  const allP=[];Object.entries(data.vacPools).forEach(([uid,yrs])=>{Object.entries(yrs).forEach(([yr,p])=>{allP.push({userId:uid,year:Number(yr),...p});});});allP.sort((a,b)=>b.year-a.year);
  return<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:0}}>Usuarios ({data.users.length})</h2><Btn onClick={()=>{setEu(null);setModal("eu");}} icon="plus" size="sm">Nuevo</Btn></div><Card style={{marginBottom:20}}><Table columns={[{label:"Nombre",key:"name"},{label:"Email",key:"email"},{label:"Rol",render:r=><Badge text={r.role} type={r.role}/>},{label:"Estado",render:r=><Badge text={r.active?"Activo":"Off"} type={r.active?"activo":"inactivo"}/>},{label:"Responsable",render:r=>getUserName(r.responsableId)},{label:"",render:r=>r.role!=="admin"?<Btn size="sm" color={C.blue} onClick={()=>{setEu(r);setModal("eu");}} icon="edit">Editar</Btn>:null}]} data={data.users}/></Card>
    <h3 style={{fontSize:18,fontWeight:700,marginBottom:12}}>Pools Vacacionales</h3><Card style={{marginBottom:12}}><div style={{display:"flex",gap:12,flexWrap:"wrap",alignItems:"flex-end"}}><div style={{flex:1,minWidth:160}}><Input label="Usuario" type="select" value={pu} onChange={setPu} options={data.users.filter(u=>u.role!=="admin").map(u=>({value:u.id,label:u.name}))}/></div><div style={{width:90}}><Input label="Año" type="number" value={py} onChange={v=>setPy(Number(v))}/></div><div style={{width:80}}><Input label="Días" type="number" value={pd} onChange={setPd}/></div><Btn onClick={ap} icon="plus" style={{marginBottom:16}}>Activar</Btn></div></Card><Card><Table columns={[{label:"Usuario",render:r=>getUserName(r.userId)},{label:"Año",render:r=>r.year},{label:"Total",render:r=>r.total},{label:"Estado",render:r=><Badge text={r.active?"Activo":"Bloq."} type={r.active?"activo":"inactivo"}/>},{label:"",render:r=><Btn size="sm" color={r.active?C.amber:C.green} onClick={()=>tp(r.userId,r.year)}>{r.active?"Bloq.":"Act."}</Btn>}]} data={allP.slice(0,60)}/></Card>
    {modal==="eu"&&<Modal title={eu?"Editar":"Nuevo usuario"} onClose={()=>{setModal(null);setEu(null);}}><UF user={eu} resps={resps} onS={sv}/></Modal>}</div>;}
function UF({user,resps,onS}){const[n,setN]=useState(user?.name||"");const[e,setE]=useState(user?.email||"");const[pw,setPw]=useState("");const[r,setR]=useState(user?.role||"usuario");const[a,setA]=useState(user?.active??true);const[rp,setRp]=useState(user?.responsableId||"");return<><Input label="Nombre" value={n} onChange={setN} required/><Input label="Email" value={e} onChange={setE} type="email" required/><Input label={user?"Contraseña (vacío=sin cambio)":"Contraseña"} value={pw} onChange={setPw} type="password" required={!user}/><Input label="Rol" type="select" value={r} onChange={setR} options={[{value:"usuario",label:"Usuario"},{value:"responsable",label:"Responsable"},{value:"admin",label:"Admin"}]}/><Input label="Responsable" type="select" value={rp} onChange={setRp} options={[{value:"",label:"—"},...resps.map(r=>({value:r.id,label:r.name}))]}/><div style={{marginBottom:16,display:"flex",alignItems:"center",gap:8}}><input type="checkbox" checked={a} onChange={ev=>setA(ev.target.checked)} id="cb-a"/><label htmlFor="cb-a" style={{fontSize:14}}>Activo</label></div><Btn full onClick={()=>onS({id:user?.id,name:n,email:e,pw,role:r,active:a,resp:rp})} icon="save" disabled={!n||!e||(!user&&!pw)}>{user?"Guardar":"Crear"}</Btn></>;}

// CONFIG
function TabConfig({data,updateData,showToast,getUserName}){const[et,setEt]=useState(null);const[nI,setNI]=useState("");const[nN,setNN]=useState("");const[nD,setND]=useState("0");const[su,setSu]=useState("");const[uo,setUo]=useState({});const[ur,setUr]=useState("");
  function togT(id){updateData(d=>{d.config.incidencias[id].activo=!d.config.incidencias[id].activo;});}function svT(id,l,d){updateData(x=>{x.config.incidencias[id].label=l;x.config.incidencias[id].diasDefecto=Number(d);});setEt(null);showToast("OK");}function addT(){if(!nI||!nN){showToast("Complete","error");return;}if(data.config.incidencias[nI]){showToast("ID existe","error");return;}updateData(d=>{d.config.incidencias[nI]={label:nN,diasDefecto:Number(nD),activo:true};});setNI("");setNN("");setND("0");showToast("Añadido");}
  function loadUC(uid){setSu(uid);if(uid){const uc=data.userConfig[uid]||{};setUr(uc.horasExtraPorDia?.toString()||"");const o={};Object.keys(data.config.incidencias).forEach(k=>{o[k]=uc.incidencias?.[k]?.dias?.toString()||"";});setUo(o);}}
  function svUC(){if(!su)return;updateData(d=>{if(!d.userConfig[su])d.userConfig[su]={};if(ur!=="")d.userConfig[su].horasExtraPorDia=Number(ur);const inc={};Object.entries(uo).forEach(([k,v])=>{if(v!=="")inc[k]={dias:Number(v)};});d.userConfig[su].incidencias=inc;});showToast("Guardado");}
  return<div><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:"0 0 20px"}}>Configuración</h2><Card style={{marginBottom:20}}><h3 style={{fontSize:16,fontWeight:700,margin:"0 0 12px"}}>Tipos de incidencia</h3><Table columns={[{label:"ID",key:"id"},{label:"Nombre",key:"label"},{label:"Días",render:r=>r.diasDefecto===0?"Ilim.":r.diasDefecto},{label:"Act.",render:r=><Badge text={r.activo?"Sí":"No"} type={r.activo?"activo":"inactivo"}/>},{label:"",render:r=><div style={{display:"flex",gap:4}}><Btn size="sm" color={C.blue} onClick={()=>setEt(r)} icon="edit"/><Btn size="sm" color={r.activo?C.amber:C.green} onClick={()=>togT(r.id)}>{r.activo?"Off":"On"}</Btn></div>}]} data={Object.entries(data.config.incidencias).map(([k,v])=>({id:k,...v}))}/>
    {et&&<div style={{marginTop:12,padding:12,background:C.grayBg,borderRadius:8}}><ETF ini={et} onS={(l,d)=>svT(et.id,l,d)} onC={()=>setEt(null)}/></div>}
    <div style={{marginTop:12,padding:12,background:C.grayBg,borderRadius:8}}><div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"flex-end"}}><div style={{flex:1,minWidth:100}}><Input label="ID" value={nI} onChange={setNI}/></div><div style={{flex:2,minWidth:160}}><Input label="Nombre" value={nN} onChange={setNN}/></div><div style={{width:70}}><Input label="Días" type="number" value={nD} onChange={setND}/></div><Btn onClick={addT} icon="plus" style={{marginBottom:16}}>Añadir</Btn></div></div></Card>
    <Card style={{marginBottom:20}}><h3 style={{fontSize:16,fontWeight:700,margin:"0 0 12px"}}>Ratio horas extra</h3><div style={{display:"flex",gap:12,alignItems:"flex-end"}}><div style={{width:120}}><Input label="Horas/día" type="number" value={data.config.horasExtraPorDia} onChange={v=>updateData(d=>{d.config.horasExtraPorDia=Number(v);})}/></div><span style={{fontSize:13,color:C.textLight,paddingBottom:20}}>{data.config.horasExtraPorDia}h = 1 día</span></div></Card>
    <Card><h3 style={{fontSize:16,fontWeight:700,margin:"0 0 12px"}}>Override por usuario</h3><Input label="Usuario" type="select" value={su} onChange={loadUC} options={[{value:"",label:"—"},...data.users.filter(u=>u.role!=="admin").map(u=>({value:u.id,label:u.name}))]}/>{su&&<><Input label={`Ratio (global: ${data.config.horasExtraPorDia})`} type="number" value={ur} onChange={setUr} placeholder={String(data.config.horasExtraPorDia)}/><div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))",gap:6}}>{Object.entries(data.config.incidencias).filter(([,v])=>v.activo).map(([k,v])=><Input key={k} label={`${v.label} (${v.diasDefecto===0?"ilim.":v.diasDefecto})`} type="number" value={uo[k]||""} onChange={val=>setUo(p=>({...p,[k]:val}))} placeholder={String(v.diasDefecto)}/>)}</div><Btn onClick={svUC} icon="save" style={{marginTop:8}}>Guardar</Btn></>}</Card></div>;}
function ETF({ini,onS,onC}){const[l,setL]=useState(ini.label);const[d,setD]=useState(String(ini.diasDefecto));return<div style={{display:"flex",gap:8,alignItems:"flex-end",flexWrap:"wrap"}}><div style={{flex:2}}><Input label="Nombre" value={l} onChange={setL}/></div><div style={{width:70}}><Input label="Días" type="number" value={d} onChange={setD}/></div><Btn onClick={()=>onS(l,d)} icon="check" color={C.green} style={{marginBottom:16}}>OK</Btn><Btn onClick={onC} color={C.gray} style={{marginBottom:16}}>X</Btn></div>;}

// CALENDARIO
function TabCalendario({data,updateData,showToast}){const[nd,setNd]=useState("");const[nn,setNn]=useState("");function add(){if(!nd){showToast("Fecha","error");return;}if(data.festivos.includes(nd)){showToast("Existe","error");return;}updateData(d=>d.festivos.push(nd));setNd("");setNn("");showToast("Añadido");}function rm(d){updateData(x=>{x.festivos=x.festivos.filter(f=>f!==d);});showToast("Eliminado");}return<div><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:"0 0 20px"}}>Calendario</h2><div style={{display:"flex",gap:12,marginBottom:20,flexWrap:"wrap"}}><KpiCard icon="calendar" label="Festivos" value={data.festivos.length} color={C.red}/><KpiCard icon="palmtree" label="Vacaciones convenio" value="22 días" color={C.green}/></div><Card style={{marginBottom:16}}><div style={{display:"flex",gap:12,alignItems:"flex-end",flexWrap:"wrap"}}><div style={{flex:1,minWidth:160}}><Input label="Fecha" type="date" value={nd} onChange={setNd}/></div><div style={{flex:2,minWidth:200}}><Input label="Nombre" value={nn} onChange={setNn} placeholder="Ej: Navidad"/></div><Btn onClick={add} icon="plus" style={{marginBottom:16}}>Añadir</Btn></div></Card><Card><Table columns={[{label:"Fecha",render:r=>fmtDate(r)},{label:"Día",render:r=>DAYS_ES[new Date(r).getDay()]},{label:"",render:r=><Btn size="sm" color={C.danger} onClick={()=>rm(r)} icon="trash"/>}]} data={[...data.festivos].sort()}/></Card></div>;}

// DATOS
function TabDatos({data,updateData,showToast,getUserName}){function eCSV(t){let h,r,fn;if(t==="f"){h=["ID","Usuario","Fecha","Tipo","Hora"];r=data.fichajes.map(f=>[f.id,getUserName(f.userId),f.date,f.type,fmtDateTime(f.serverTime)]);fn="fichajes.csv";}else if(t==="s"){h=["ID","Usuario","Tipo","Desde","Hasta","Estado"];r=data.solicitudes.map(s=>[s.id,getUserName(s.userId),s.type,fmtDate(s.dateFrom),fmtDate(s.dateTo),s.status]);fn="solicitudes.csv";}else{h=["ID","Usuario","Horas","Motivo"];r=data.horasExtra.map(x=>[x.id,getUserName(x.userId),x.horas,x.motivo]);fn="horas_extra.csv";}downloadFile(genCSV(h,r),fn);showToast(`${fn} exportado`);}function eJSON(){downloadFile(JSON.stringify(data,null,2),"backup.json","application/json");showToast("Exportado");}function iJSON(e){const f=e.target.files?.[0];if(!f)return;if(!window.confirm("¿Reemplazar TODOS los datos?"))return;const r=new FileReader();r.onload=ev=>{try{const d=JSON.parse(ev.target.result);if(d.users&&d.config){updateData(()=>d);showToast("Importado");}else showToast("Inválido","error");}catch{showToast("Error","error");}};r.readAsText(f);}return<div><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:"0 0 20px"}}>Import / Export</h2><Card style={{marginBottom:16}}><h3 style={{fontSize:16,fontWeight:700,margin:"0 0 12px"}}>CSV</h3><div style={{display:"flex",gap:12,flexWrap:"wrap"}}><Btn onClick={()=>eCSV("f")} icon="download" color={C.blue}>Fichajes ({data.fichajes.length})</Btn><Btn onClick={()=>eCSV("s")} icon="download" color={C.green}>Solicitudes ({data.solicitudes.length})</Btn><Btn onClick={()=>eCSV("h")} icon="download" color={C.amber}>Horas ({data.horasExtra.length})</Btn></div></Card><Card><h3 style={{fontSize:16,fontWeight:700,margin:"0 0 12px"}}>Backup</h3><div style={{display:"flex",gap:12,flexWrap:"wrap",alignItems:"center"}}><Btn onClick={eJSON} icon="download" color={C.purple}>JSON</Btn><label style={{display:"inline-flex",alignItems:"center",gap:8,padding:"10px 20px",borderRadius:10,border:`1px solid ${C.border}`,cursor:"pointer",fontSize:14,fontWeight:600}}><Icon name="upload" size={16}/>Importar<input type="file" accept=".json" onChange={iJSON} style={{display:"none"}}/></label></div></Card></div>;}

// ACCESOS
function TabAccesos({data}){const[f,setF]=useState("all");const logs=data.accessLogs.filter(l=>{if(f==="ok")return l.success;if(f==="fail")return!l.success;return true;});const t=data.accessLogs.length;const fl=data.accessLogs.filter(l=>!l.success).length;const ips=new Set(data.accessLogs.map(l=>l.ip)).size;return<div><h2 style={{fontSize:22,fontWeight:800,color:C.text,margin:"0 0 20px"}}>Accesos</h2><div style={{display:"flex",gap:12,marginBottom:16,flexWrap:"wrap"}}><KpiCard icon="shield" label="Total" value={t} color={C.blue}/><KpiCard icon="alert" label="Fallidos" value={fl} color={C.danger}/><KpiCard icon="users" label="IPs" value={ips} color={C.purple}/></div><div style={{display:"flex",gap:6,marginBottom:12}}>{[["all","Todos"],["ok","OK"],["fail","Fallos"]].map(([k,l])=><button key={k} onClick={()=>setF(k)} style={{padding:"5px 14px",borderRadius:8,border:`1px solid ${f===k?C.red:C.border}`,background:f===k?C.red:C.white,color:f===k?C.white:C.text,fontSize:13,fontWeight:600,cursor:"pointer"}}>{l}</button>)}</div><Card><Table columns={[{label:"Fecha",render:r=>fmtDateTime(r.timestamp)},{label:"Email",key:"email"},{label:"Resultado",render:r=><Badge text={r.success?"OK":"FALLO"} type={r.success?"ok":"fallo"}/>},{label:"Motivo",render:r=>r.reason||"—"},{label:"Plataforma",key:"platform"},{label:"IP",key:"ip"}]} data={logs} rowStyle={r=>!r.success?{background:"#FEF2F2"}:{}}/></Card></div>;}
